import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Container,
  Paper,
  Typography,
  Box,
  Button,
  Card,
  CardContent,
  TextField,
  Alert,
  CircularProgress,
  Chip,
} from '@mui/material';
import {
  Event,
  LocationOn,
  CalendarToday,
  CreditCard,
  ArrowBack,
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import axios from 'axios';
import toast from 'react-hot-toast';

const BookingForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [booking, setBooking] = useState(false);
  const [paymentInfo, setPaymentInfo] = useState({
    cardNumber: '',
    expiryDate: '',
    cvv: '',
    name: '',
  });
  const [errors, setErrors] = useState({});

  useEffect(() => {
    loadEvent();
  }, [id]);

  const loadEvent = async () => {
    try {
      const response = await axios.get(`/events/${id}`);
      setEvent(response.data);
    } catch (error) {
      console.error('Error loading event:', error);
      toast.error('Failed to load event details');
      navigate('/events');
    } finally {
      setLoading(false);
    }
  };

  const handlePaymentChange = (e) => {
    const { name, value } = e.target;
    setPaymentInfo({
      ...paymentInfo,
      [name]: value,
    });
    if (errors[name]) {
      setErrors({
        ...errors,
        [name]: '',
      });
    }
  };

  const validatePayment = () => {
    const newErrors = {};

    if (!paymentInfo.cardNumber.trim()) {
      newErrors.cardNumber = 'Card number is required';
    } else if (!/^\d{16}$/.test(paymentInfo.cardNumber.replace(/\s/g, ''))) {
      newErrors.cardNumber = 'Please enter a valid 16-digit card number';
    }

    if (!paymentInfo.expiryDate.trim()) {
      newErrors.expiryDate = 'Expiry date is required';
    } else if (!/^(0[1-9]|1[0-2])\/\d{2}$/.test(paymentInfo.expiryDate)) {
      newErrors.expiryDate = 'Please enter a valid expiry date (MM/YY)';
    }

    if (!paymentInfo.cvv.trim()) {
      newErrors.cvv = 'CVV is required';
    } else if (!/^\d{3,4}$/.test(paymentInfo.cvv)) {
      newErrors.cvv = 'Please enter a valid CVV';
    }

    if (!paymentInfo.name.trim()) {
      newErrors.name = 'Cardholder name is required';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleBooking = async () => {
    if (event.price > 0 && !validatePayment()) {
      return;
    }

    setBooking(true);
    try {
      const response = await axios.post(`/events/${id}/book`);
      toast.success('Booking successful!');

      // Simulate payment processing for paid events
      if (event.price > 0) {
        await new Promise(resolve => setTimeout(resolve, 2000)); // Simulate payment delay
        toast.success('Payment processed successfully!');
      }

      navigate('/dashboard');
    } catch (error) {
      console.error('Error booking event:', error);
      const errorMessage = error.response?.data?.message || 'Booking failed';
      toast.error(errorMessage);
    } finally {
      setBooking(false);
    }
  };

  const formatCardNumber = (value) => {
    const v = value.replace(/\s+/g, '').replace(/[^0-9]/gi, '');
    const matches = v.match(/\d{4,16}/g);
    const match = matches && matches[0] || '';
    const parts = [];
    for (let i = 0, len = match.length; i < len; i += 4) {
      parts.push(match.substring(i, i + 4));
    }
    if (parts.length) {
      return parts.join(' ');
    } else {
      return v;
    }
  };

  const formatExpiryDate = (value) => {
    const v = value.replace(/\D/g, '');
    if (v.length >= 2) {
      return v.substring(0, 2) + '/' + v.substring(2, 4);
    }
    return v;
  };

  if (loading) {
    return (
      <Container maxWidth="md" sx={{ py: 8 }}>
        <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
          <CircularProgress sx={{ color: '#6366f1' }} />
        </Box>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container maxWidth="md" sx={{ py: 8 }}>
        <Typography variant="h5" align="center">
          Event not found
        </Typography>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <Button
          startIcon={<ArrowBack />}
          onClick={() => navigate(`/events/${id}`)}
          sx={{ mb: 3, color: 'rgba(255, 255, 255, 0.7)' }}
        >
          Back to Event
        </Button>

        <Typography
          variant="h3"
          component="h1"
          sx={{
            mb: 4,
            textAlign: 'center',
            background: 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            fontWeight: 'bold',
          }}
        >
          Book Your Spot
        </Typography>

        {/* Event Summary */}
        <Card
          sx={{
            mb: 4,
            background: 'rgba(255, 255, 255, 0.05)',
            backdropFilter: 'blur(10px)',
            border: '1px solid rgba(255, 255, 255, 0.1)',
          }}
        >
          <CardContent>
            <Typography variant="h5" sx={{ mb: 2, fontWeight: 'bold', color: 'white' }}>
              {event.title}
            </Typography>

            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2, mb: 2 }}>
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                <CalendarToday sx={{ mr: 1, color: '#6366f1' }} />
                <Typography sx={{ color: 'white' }}>
                  {new Date(event.date).toLocaleDateString('en-US', {
                    weekday: 'long',
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit',
                  })}
                </Typography>
              </Box>

              {event.location && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <LocationOn sx={{ mr: 1, color: '#8b5cf6' }} />
                  <Typography sx={{ color: 'white' }}>{event.location}</Typography>
                </Box>
              )}
            </Box>

            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <Typography variant="h6" sx={{ color: 'white', fontWeight: 'bold' }}>
                Total: {event.price > 0 ? `$${event.price}` : 'Free'}
              </Typography>
              <Chip
                label={event.price > 0 ? 'Paid Event' : 'Free Event'}
                sx={{
                  background: event.price > 0
                    ? 'linear-gradient(45deg, #10b981 30%, #059669 90%)'
                    : 'linear-gradient(45deg, #06b6d4 30%, #0891b2 90%)',
                  color: 'white',
                }}
              />
            </Box>
          </CardContent>
        </Card>

        {/* Payment Form (only for paid events) */}
        {event.price > 0 && (
          <Paper
            sx={{
              p: 4,
              mb: 4,
              background: 'rgba(255, 255, 255, 0.05)',
              backdropFilter: 'blur(10px)',
              border: '1px solid rgba(255, 255, 255, 0.1)',
            }}
          >
            <Typography variant="h6" sx={{ mb: 3, color: 'white', fontWeight: 'bold' }}>
              Payment Information
            </Typography>

            <Alert severity="info" sx={{ mb: 3 }}>
              This is a demo payment form. In a real application, this would integrate with a payment processor like Stripe.
            </Alert>

            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
              <TextField
                fullWidth
                label="Cardholder Name"
                name="name"
                value={paymentInfo.name}
                onChange={handlePaymentChange}
                error={!!errors.name}
                helperText={errors.name}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    background: 'rgba(255, 255, 255, 0.05)',
                  },
                  '& .MuiInputLabel-root': { color: 'rgba(255, 255, 255, 0.7)' },
                }}
              />

              <TextField
                fullWidth
                label="Card Number"
                name="cardNumber"
                value={paymentInfo.cardNumber}
                onChange={(e) => {
                  const formatted = formatCardNumber(e.target.value);
                  setPaymentInfo({ ...paymentInfo, cardNumber: formatted });
                }}
                error={!!errors.cardNumber}
                helperText={errors.cardNumber}
                placeholder="1234 5678 9012 3456"
                inputProps={{ maxLength: 19 }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    background: 'rgba(255, 255, 255, 0.05)',
                  },
                  '& .MuiInputLabel-root': { color: 'rgba(255, 255, 255, 0.7)' },
                }}
              />

              <Box sx={{ display: 'flex', gap: 2 }}>
                <TextField
                  fullWidth
                  label="Expiry Date"
                  name="expiryDate"
                  value={paymentInfo.expiryDate}
                  onChange={(e) => {
                    const formatted = formatExpiryDate(e.target.value);
                    setPaymentInfo({ ...paymentInfo, expiryDate: formatted });
                  }}
                  error={!!errors.expiryDate}
                  helperText={errors.expiryDate}
                  placeholder="MM/YY"
                  inputProps={{ maxLength: 5 }}
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      background: 'rgba(255, 255, 255, 0.05)',
                    },
                    '& .MuiInputLabel-root': { color: 'rgba(255, 255, 255, 0.7)' },
                  }}
                />

                <TextField
                  fullWidth
                  label="CVV"
                  name="cvv"
                  value={paymentInfo.cvv}
                  onChange={handlePaymentChange}
                  error={!!errors.cvv}
                  helperText={errors.cvv}
                  placeholder="123"
                  inputProps={{ maxLength: 4 }}
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      background: 'rgba(255, 255, 255, 0.05)',
                    },
                    '& .MuiInputLabel-root': { color: 'rgba(255, 255, 255, 0.7)' },
                  }}
                />
              </Box>
            </Box>
          </Paper>
        )}

        {/* Booking Summary */}
        <Paper
          sx={{
            p: 4,
            background: 'rgba(255, 255, 255, 0.05)',
            backdropFilter: 'blur(10px)',
            border: '1px solid rgba(255, 255, 255, 0.1)',
          }}
        >
          <Typography variant="h6" sx={{ mb: 3, color: 'white', fontWeight: 'bold' }}>
            Booking Summary
          </Typography>

          <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 2 }}>
            <Typography sx={{ color: 'rgba(255, 255, 255, 0.8)' }}>Event</Typography>
            <Typography sx={{ color: 'white' }}>{event.title}</Typography>
          </Box>

          <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 2 }}>
            <Typography sx={{ color: 'rgba(255, 255, 255, 0.8)' }}>Date</Typography>
            <Typography sx={{ color: 'white' }}>
              {new Date(event.date).toLocaleDateString()}
            </Typography>
          </Box>

          <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 3, fontWeight: 'bold' }}>
            <Typography sx={{ color: 'rgba(255, 255, 255, 0.8)' }}>Total</Typography>
            <Typography sx={{ color: 'white' }}>
              {event.price > 0 ? `$${event.price}` : 'Free'}
            </Typography>
          </Box>

          <Button
            fullWidth
            variant="contained"
            size="large"
            onClick={handleBooking}
            disabled={booking}
            startIcon={event.price > 0 ? <CreditCard /> : <Event />}
            sx={{
              py: 1.5,
              background: 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)',
              '&:hover': {
                background: 'linear-gradient(45deg, #5a5fd8 30%, #7a4fd0 90%)',
              },
              '&:disabled': {
                background: 'rgba(99, 102, 241, 0.3)',
              },
            }}
          >
            {booking ? (
              <>
                <CircularProgress size={20} sx={{ mr: 1, color: 'white' }} />
                Processing...
              </>
            ) : event.price > 0 ? (
              'Complete Payment & Book'
            ) : (
              'Book Event'
            )}
          </Button>
        </Paper>
      </motion.div>
    </Container>
  );
};

export default BookingForm;