import React, { useState, useEffect, useContext } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Container,
  Typography,
  Paper,
  Button,
  Box,
  Chip,
  Alert,
  CircularProgress,
  Card,
  CardContent,
  Avatar,
} from '@mui/material';
import {
  Event,
  LocationOn,
  CalendarToday,
  Person,
  ArrowBack,
  ShoppingCart,
  AccessTime,
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import axios from 'axios';
import toast from 'react-hot-toast';
import { AuthContext } from '../context/AuthContext';

const EventDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  const [event, setEvent] = useState(null);
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [booking, setBooking] = useState(false);

  useEffect(() => {
    loadEventDetails();
  }, [id]);

  const loadEventDetails = async () => {
    setLoading(true);
    try {
      const [eventRes, bookingsRes] = await Promise.all([
        axios.get(`/events/${id}`),
        axios.get(`/events/${id}/bookings`, {
          headers: {
            Authorization: `Bearer ${localStorage.getItem('token')}`,
          },
        }),
      ]);

      setEvent(eventRes.data);
      setBookings(bookingsRes.data);
    } catch (error) {
      console.error('Error loading event details:', error);
      toast.error('Failed to load event details');
    } finally {
      setLoading(false);
    }
  };

  const handleBookEvent = () => {
    if (!user) {
      toast.error('Please login to book events');
      navigate('/login');
      return;
    }
    navigate(`/events/${id}/book`);
  };

  const isEventFull = () => {
    return event && event.capacity && bookings.length >= event.capacity;
  };

  const isUserBooked = () => {
    return user && bookings.some(booking => booking.user_id === user.id);
  };

  const getAvailableSpots = () => {
    if (!event || !event.capacity) return 'Unlimited';
    return Math.max(0, event.capacity - bookings.length);
  };

  if (loading) {
    return (
      <Container maxWidth="md" sx={{ py: 8 }}>
        <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
          <CircularProgress sx={{ color: '#6366f1' }} />
        </Box>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container maxWidth="md" sx={{ py: 8 }}>
        <Typography variant="h5" align="center" sx={{ color: 'white' }}>
          Event not found
        </Typography>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <Button
          startIcon={<ArrowBack />}
          onClick={() => navigate('/events')}
          sx={{ mb: 3, color: 'rgba(255, 255, 255, 0.7)' }}
        >
          Back to Events
        </Button>

        <Typography
          variant="h3"
          component="h1"
          sx={{
            mb: 4,
            textAlign: 'center',
            background: 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            fontWeight: 'bold',
          }}
        >
          {event.title}
        </Typography>

        {/* Event Details Card */}
        <Card
          sx={{
            mb: 4,
            background: 'rgba(255, 255, 255, 0.05)',
            backdropFilter: 'blur(10px)',
            border: '1px solid rgba(255, 255, 255, 0.1)',
          }}
        >
          <CardContent>
            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2, mb: 3 }}>
              <Chip
                icon={<CalendarToday />}
                label={new Date(event.date).toLocaleDateString('en-US', {
                  weekday: 'long',
                  year: 'numeric',
                  month: 'long',
                  day: 'numeric',
                  hour: '2-digit',
                  minute: '2-digit',
                })}
                sx={{
                  background: 'rgba(99, 102, 241, 0.2)',
                  color: 'white',
                  border: '1px solid rgba(99, 102, 241, 0.3)',
                }}
              />

              {event.location && (
                <Chip
                  icon={<LocationOn />}
                  label={event.location}
                  sx={{
                    background: 'rgba(139, 92, 246, 0.2)',
                    color: 'white',
                    border: '1px solid rgba(139, 92, 246, 0.3)',
                  }}
                />
              )}

              <Chip
                icon={<Person />}
                label={`${bookings.length} ${bookings.length === 1 ? 'attendee' : 'attendees'}`}
                sx={{
                  background: 'rgba(16, 185, 129, 0.2)',
                  color: 'white',
                  border: '1px solid rgba(16, 185, 129, 0.3)',
                }}
              />

              {event.capacity && (
                <Chip
                  icon={<AccessTime />}
                  label={`${getAvailableSpots()} spots left`}
                  sx={{
                    background: getAvailableSpots() === 0
                      ? 'rgba(239, 68, 68, 0.2)'
                      : 'rgba(245, 158, 11, 0.2)',
                    color: 'white',
                    border: `1px solid ${getAvailableSpots() === 0 ? 'rgba(239, 68, 68, 0.3)' : 'rgba(245, 158, 11, 0.3)'}`,
                  }}
                />
              )}
            </Box>

            <Typography
              variant="body1"
              sx={{
                mb: 4,
                color: 'rgba(255, 255, 255, 0.9)',
                lineHeight: 1.6,
                fontSize: '1.1rem',
              }}
            >
              {event.description || 'No description available for this event.'}
            </Typography>

            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
              <Typography
                variant="h5"
                sx={{
                  color: 'white',
                  fontWeight: 'bold',
                  background: event.price > 0
                    ? 'linear-gradient(45deg, #10b981 30%, #059669 90%)'
                    : 'linear-gradient(45deg, #06b6d4 30%, #0891b2 90%)',
                  WebkitBackgroundClip: 'text',
                  WebkitTextFillColor: 'transparent',
                }}
              >
                {event.price > 0 ? `$${event.price}` : 'Free Event'}
              </Typography>

              {isUserBooked() && (
                <Chip
                  label="You're attending"
                  sx={{
                    background: 'linear-gradient(45deg, #10b981 30%, #059669 90%)',
                    color: 'white',
                  }}
                />
              )}
            </Box>

            <Button
              fullWidth
              variant="contained"
              size="large"
              onClick={handleBookEvent}
              disabled={isEventFull() || isUserBooked() || booking}
              startIcon={<ShoppingCart />}
              sx={{
                py: 1.5,
                background: isUserBooked()
                  ? 'linear-gradient(45deg, #10b981 30%, #059669 90%)'
                  : isEventFull()
                  ? 'linear-gradient(45deg, #ef4444 30%, #dc2626 90%)'
                  : 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)',
                '&:hover': {
                  background: isUserBooked()
                    ? 'linear-gradient(45deg, #059669 30%, #047857 90%)'
                    : isEventFull()
                    ? 'linear-gradient(45deg, #dc2626 30%, #b91c1c 90%)'
                    : 'linear-gradient(45deg, #5a5fd8 30%, #7a4fd0 90%)',
                },
                '&:disabled': {
                  background: 'rgba(99, 102, 241, 0.3)',
                },
              }}
            >
              {isUserBooked()
                ? 'Already Booked'
                : isEventFull()
                ? 'Event Full'
                : event.price > 0
                ? 'Book & Pay'
                : 'Book Event'
              }
            </Button>
          </CardContent>
        </Card>

        {/* Attendees Section */}
        {bookings.length > 0 && (
          <Card
            sx={{
              background: 'rgba(255, 255, 255, 0.05)',
              backdropFilter: 'blur(10px)',
              border: '1px solid rgba(255, 255, 255, 0.1)',
            }}
          >
            <CardContent>
              <Typography
                variant="h5"
                sx={{
                  mb: 3,
                  color: 'white',
                  fontWeight: 'bold',
                }}
              >
                Attendees ({bookings.length})
              </Typography>

              <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
                {bookings.slice(0, 10).map((booking, index) => (
                  <Box
                    key={index}
                    sx={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 1,
                      background: 'rgba(255, 255, 255, 0.05)',
                      borderRadius: 2,
                      px: 2,
                      py: 1,
                      border: '1px solid rgba(255, 255, 255, 0.1)',
                    }}
                  >
                    <Avatar
                      sx={{
                        width: 32,
                        height: 32,
                        background: 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)',
                        fontSize: '0.875rem',
                      }}
                    >
                      {booking.user?.name?.charAt(0)?.toUpperCase() || 'U'}
                    </Avatar>
                    <Typography sx={{ color: 'white', fontSize: '0.875rem' }}>
                      {booking.user?.name || 'Anonymous'}
                    </Typography>
                  </Box>
                ))}

                {bookings.length > 10 && (
                  <Box
                    sx={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 1,
                      background: 'rgba(255, 255, 255, 0.05)',
                      borderRadius: 2,
                      px: 2,
                      py: 1,
                      border: '1px solid rgba(255, 255, 255, 0.1)',
                    }}
                  >
                    <Typography sx={{ color: 'rgba(255, 255, 255, 0.7)', fontSize: '0.875rem' }}>
                      +{bookings.length - 10} more
                    </Typography>
                  </Box>
                )}
              </Box>
            </CardContent>
          </Card>
        )}
      </motion.div>
    </Container>
  );
};

export default EventDetails;