import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Container,
  Typography,
  Box,
  Grid,
  Card,
  CardContent,
  Button,
  Chip,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
} from '@mui/material';
import {
  Event,
  LocationOn,
  CalendarToday,
  Delete,
  Add,
  Dashboard as DashboardIcon,
  Person,
  AdminPanelSettings,
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import axios from 'axios';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deleteDialog, setDeleteDialog] = useState({ open: false, bookingId: null });

  useEffect(() => {
    loadBookings();
  }, []);

  const loadBookings = async () => {
    try {
      const response = await axios.get('/bookings');
      setBookings(response.data);
    } catch (error) {
      console.error('Error loading bookings:', error);
      toast.error('Failed to load bookings');
    } finally {
      setLoading(false);
    }
  };

  const handleCancelBooking = async (bookingId) => {
    try {
      await axios.delete(`/bookings/${bookingId}`);
      toast.success('Booking cancelled successfully');
      loadBookings();
      setDeleteDialog({ open: false, bookingId: null });
    } catch (error) {
      console.error('Error cancelling booking:', error);
      toast.error('Failed to cancel booking');
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'confirmed':
        return 'success';
      case 'pending':
        return 'warning';
      case 'cancelled':
        return 'error';
      default:
        return 'default';
    }
  };

  if (loading) {
    return (
      <Container maxWidth="lg" sx={{ py: 4 }}>
        <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
          <Typography>Loading dashboard...</Typography>
        </Box>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        {/* Header */}
        <Box sx={{ mb: 4, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Box>
            <Typography
              variant="h3"
              component="h1"
              sx={{
                mb: 1,
                background: 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                fontWeight: 'bold',
              }}
            >
              Welcome back, {user.username}!
            </Typography>
            <Typography variant="body1" sx={{ color: 'rgba(255, 255, 255, 0.7)' }}>
              Manage your events and bookings
            </Typography>
          </Box>

          {user.is_admin && (
            <Button
              variant="contained"
              startIcon={<AdminPanelSettings />}
              onClick={() => navigate('/admin')}
              sx={{
                background: 'linear-gradient(45deg, #f59e0b 30%, #d97706 90%)',
                '&:hover': {
                  background: 'linear-gradient(45deg, #d97706 30%, #b45309 90%)',
                },
              }}
            >
              Admin Panel
            </Button>
          )}
        </Box>

        {/* Stats Cards */}
        <Grid container spacing={3} sx={{ mb: 4 }}>
          <Grid item xs={12} sm={6} md={3}>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.1 }}
            >
              <Card
                sx={{
                  background: 'rgba(255, 255, 255, 0.05)',
                  backdropFilter: 'blur(10px)',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                }}
              >
                <CardContent sx={{ textAlign: 'center' }}>
                  <DashboardIcon sx={{ fontSize: 48, color: '#6366f1', mb: 1 }} />
                  <Typography variant="h4" sx={{ fontWeight: 'bold', color: 'white' }}>
                    {bookings.length}
                  </Typography>
                  <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.7)' }}>
                    Total Bookings
                  </Typography>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          <Grid item xs={12} sm={6} md={3}>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.2 }}
            >
              <Card
                sx={{
                  background: 'rgba(255, 255, 255, 0.05)',
                  backdropFilter: 'blur(10px)',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                }}
              >
                <CardContent sx={{ textAlign: 'center' }}>
                  <Event sx={{ fontSize: 48, color: '#8b5cf6', mb: 1 }} />
                  <Typography variant="h4" sx={{ fontWeight: 'bold', color: 'white' }}>
                    {bookings.filter(b => b.status === 'confirmed').length}
                  </Typography>
                  <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.7)' }}>
                    Active Bookings
                  </Typography>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          <Grid item xs={12} sm={6} md={3}>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.3 }}
            >
              <Card
                sx={{
                  background: 'rgba(255, 255, 255, 0.05)',
                  backdropFilter: 'blur(10px)',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                }}
              >
                <CardContent sx={{ textAlign: 'center' }}>
                  <Person sx={{ fontSize: 48, color: '#10b981', mb: 1 }} />
                  <Typography variant="h4" sx={{ fontWeight: 'bold', color: 'white' }}>
                    {user.username}
                  </Typography>
                  <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.7)' }}>
                    {user.is_admin ? 'Administrator' : 'Member'}
                  </Typography>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          <Grid item xs={12} sm={6} md={3}>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.4 }}
            >
              <Card
                sx={{
                  background: 'rgba(255, 255, 255, 0.05)',
                  backdropFilter: 'blur(10px)',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                }}
              >
                <CardContent sx={{ textAlign: 'center' }}>
                  <Add sx={{ fontSize: 48, color: '#f59e0b', mb: 1 }} />
                  <Button
                    variant="contained"
                    fullWidth
                    onClick={() => navigate('/create-event')}
                    sx={{
                      background: 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)',
                      '&:hover': {
                        background: 'linear-gradient(45deg, #5a5fd8 30%, #7a4fd0 90%)',
                      },
                    }}
                  >
                    Create Event
                  </Button>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>
        </Grid>

        {/* Bookings Section */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.5 }}
        >
          <Card
            sx={{
              background: 'rgba(255, 255, 255, 0.05)',
              backdropFilter: 'blur(10px)',
              border: '1px solid rgba(255, 255, 255, 0.1)',
            }}
          >
            <CardContent>
              <Typography variant="h5" sx={{ mb: 3, fontWeight: 'bold', color: 'white' }}>
                My Bookings
              </Typography>

              {bookings.length === 0 ? (
                <Box textAlign="center" py={4}>
                  <Typography variant="body1" sx={{ color: 'rgba(255, 255, 255, 0.7)', mb: 2 }}>
                    You haven't booked any events yet.
                  </Typography>
                  <Button
                    variant="contained"
                    onClick={() => navigate('/events')}
                    startIcon={<Event />}
                    sx={{
                      background: 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)',
                      '&:hover': {
                        background: 'linear-gradient(45deg, #5a5fd8 30%, #7a4fd0 90%)',
                      },
                    }}
                  >
                    Browse Events
                  </Button>
                </Box>
              ) : (
                <List>
                  {bookings.map((booking, index) => (
                    <React.Fragment key={booking.id}>
                      <ListItem
                        sx={{
                          background: 'rgba(255, 255, 255, 0.02)',
                          borderRadius: 2,
                          mb: 1,
                        }}
                      >
                        <ListItemAvatar>
                          <Avatar sx={{ background: 'linear-gradient(45deg, #6366f1 30%, #8b5cf6 90%)' }}>
                            <Event />
                          </Avatar>
                        </ListItemAvatar>
                        <ListItemText
                          primary={
                            <Typography variant="h6" sx={{ color: 'white', fontWeight: 'bold' }}>
                              {booking.event_title}
                            </Typography>
                          }
                          secondary={
                            <Box>
                              <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.7)', mb: 1 }}>
                                Booked on: {formatDate(booking.booking_date)}
                              </Typography>
                              <Box sx={{ display: 'flex', gap: 1, alignItems: 'center' }}>
                                <Chip
                                  label={booking.status}
                                  size="small"
                                  color={getStatusColor(booking.status)}
                                  sx={{ textTransform: 'capitalize' }}
                                />
                                <Chip
                                  label={booking.payment_status}
                                  size="small"
                                  variant="outlined"
                                  sx={{
                                    borderColor: 'rgba(255, 255, 255, 0.3)',
                                    color: 'white',
                                    textTransform: 'capitalize',
                                  }}
                                />
                              </Box>
                            </Box>
                          }
                        />
                        {booking.status === 'confirmed' && (
                          <IconButton
                            edge="end"
                            onClick={() => setDeleteDialog({ open: true, bookingId: booking.id })}
                            sx={{ color: '#ef4444' }}
                          >
                            <Delete />
                          </IconButton>
                        )}
                      </ListItem>
                      {index < bookings.length - 1 && <Divider sx={{ background: 'rgba(255, 255, 255, 0.1)' }} />}
                    </React.Fragment>
                  ))}
                </List>
              )}
            </CardContent>
          </Card>
        </motion.div>
      </motion.div>

      {/* Delete Confirmation Dialog */}
      <Dialog
        open={deleteDialog.open}
        onClose={() => setDeleteDialog({ open: false, bookingId: null })}
        PaperProps={{
          sx: {
            background: 'rgba(15, 15, 35, 0.9)',
            backdropFilter: 'blur(20px)',
            border: '1px solid rgba(255, 255, 255, 0.1)',
          },
        }}
      >
        <DialogTitle sx={{ color: 'white' }}>Cancel Booking</DialogTitle>
        <DialogContent>
          <Typography sx={{ color: 'rgba(255, 255, 255, 0.7)' }}>
            Are you sure you want to cancel this booking? This action cannot be undone.
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button
            onClick={() => setDeleteDialog({ open: false, bookingId: null })}
            sx={{ color: 'rgba(255, 255, 255, 0.7)' }}
          >
            Keep Booking
          </Button>
          <Button
            onClick={() => handleCancelBooking(deleteDialog.bookingId)}
            variant="contained"
            color="error"
          >
            Cancel Booking
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default Dashboard;